   218→/* Proleptic Gregorian Calendar, 1BCE = year 0 */
   219→
   220→int lutil_tm2gtime( struct lutil_tm *tm, struct lutil_timet *tt )
   221→{
   222→	static int moffset[12] = {
   223→		0, 31, 59, 90, 120,
   224→		151, 181, 212, 243,
   225→		273, 304, 334 };
   226→	int sec, year;
   227→	long tmp;
   228→
   229→	tt->tt_nsec = tm->tm_nsec;
   230→
   231→	/* tm->tm_year is years since 1900 */
   232→	/* calculate days from 0000 */
   233→	year = tm->tm_year + 1900;
   234→	tmp = year * 365;
   235→
   236→	/* add in leap days */
   237→	sec = (year - 1) / 4;
   238→	tmp += sec;
   239→	sec /= 25;
   240→	tmp -= sec;
   241→	sec /= 4;
   242→	tmp += sec;
   243→	/* Year 0000 was a leap year */
   244→	if (year > 0)
   245→		tmp++;
   246→
   247→	/* calculate days from months */
   248→	tmp += moffset[tm->tm_mon];
   249→
   250→	/* add in this year's leap day, if any */
   251→	if (tm->tm_mon > 1) {
   252→		sec = (year % 4) ? 0 : (year % 100) ? 1 : (year % 400) ? 0 : 1;
   253→		tmp += sec;
   254→	}
   255→
   256→	/* add in days in this month */
   257→	tmp += (tm->tm_mday - 1);
   258→
   259→	/* this function can handle a range of about 17408 years... */
   260→	/* 86400 seconds in a day, divided by 128 = 675 */
   261→	tmp *= 675;
   262→
   263→	/* move high 7 bits into tt_gsec */
   264→	tt->tt_gsec = tmp >> 25;
   265→	tmp -= tt->tt_gsec << 25;
   266→
   267→	/* toggle sign bit, keep positive greater than negative */
   268→	tt->tt_gsec &= 0x7f;
   269→	tt->tt_gsec ^= 0x40;
   270→
   271→	/* get hours */
   272→	sec = tm->tm_hour;
   273→
   274→	/* convert to minutes */
   275→	sec *= 60L;
   276→	sec += tm->tm_min;
   277→
   278→	/* convert to seconds */
   279→	sec *= 60L;
   280→	sec += tm->tm_sec;
   281→	
   282→	/* add remaining seconds */
   283→	tmp <<= 7;
   284→	tmp += sec;
   285→	tt->tt_sec = tmp;
   286→
   287→	/* return success */
   288→	return 0;
   289→}
