   291→int lutil_parsetime( char *atm, struct lutil_tm *tm )
   292→{
   293→	while (atm && tm) {
   294→		char *ptr;
   295→		unsigned i, fracs;
   296→		int neg = 0;
   297→
   298→		if (*atm == '-') {
   299→			neg = 1;
   300→			atm++;
   301→		}
   302→		ptr = atm;
   303→
   304→		/* Is the stamp reasonably long? */
   305→		for (i=0; isdigit((unsigned char) atm[i]); i++);
   306→		if (i < sizeof("00000101000000")-1)
   307→			break;
   308→
   309→		/*
   310→		 * parse the time into a struct tm
   311→		 */
   312→		/* 4 digit year to year - 1900 */
   313→		tm->tm_year = *ptr++ - '0';
   314→		tm->tm_year *= 10; tm->tm_year += *ptr++ - '0';
   315→		tm->tm_year *= 10; tm->tm_year += *ptr++ - '0';
   316→		tm->tm_year *= 10; tm->tm_year += *ptr++ - '0';
   317→		if (neg)
   318→			tm->tm_year = -tm->tm_year;
   319→		tm->tm_year -= 1900;
   320→		/* month 01-12 to 0-11 */
   321→		tm->tm_mon = *ptr++ - '0';
   322→		tm->tm_mon *=10; tm->tm_mon += *ptr++ - '0';
   323→		if (tm->tm_mon < 1 || tm->tm_mon > 12) break;
   324→		tm->tm_mon--;
   325→
   326→		/* day of month 01-31 */
   327→		tm->tm_mday = *ptr++ - '0';
   328→		tm->tm_mday *=10; tm->tm_mday += *ptr++ - '0';
   329→		if (tm->tm_mday < 1 || tm->tm_mday > 31) break;
   330→
   331→		/* Hour 00-23 */
   332→		tm->tm_hour = *ptr++ - '0';
   333→		tm->tm_hour *=10; tm->tm_hour += *ptr++ - '0';
   334→		if (tm->tm_hour < 0 || tm->tm_hour > 23) break;
   335→
   336→		/* Minute 00-59 */
   337→		tm->tm_min = *ptr++ - '0';
   338→		tm->tm_min *=10; tm->tm_min += *ptr++ - '0';
   339→		if (tm->tm_min < 0 || tm->tm_min > 59) break;
   340→
   341→		/* Second 00-61 */
   342→		tm->tm_sec = *ptr++ - '0';
   343→		tm->tm_sec *=10; tm->tm_sec += *ptr++ - '0';
   344→		if (tm->tm_sec < 0 || tm->tm_sec > 61) break;
   345→
   346→		/* Fractions of seconds */
   347→		if ( *ptr == '.' ) {
   348→			ptr++;
   349→			for (i = 0, fracs = 0; isdigit((unsigned char) *ptr); ) {
   350→				i*=10; i+= *ptr++ - '0';
   351→				fracs++;
   352→			}
   353→			tm->tm_nsec = i;
   354→			if (i) {
   355→				for (i = fracs; i<9; i++)
   356→					tm->tm_nsec *= 10;
   357→			}
   358→		} else {
   359→			tm->tm_nsec = 0;
   360→		}
   361→		tm->tm_usub = 0;
   362→
   363→		/* Must be UTC */
   364→		if (*ptr != 'Z') break;
   365→
   366→		return 0;
   367→	}
   368→	return -1;
   369→}
