   371→/* strcopy is like strcpy except it returns a pointer to the trailing NUL of
   372→ * the result string. This allows fast construction of catenated strings
   373→ * without the overhead of strlen/strcat.
   374→ */
   375→char *
   376→lutil_strcopy(
   377→	char *a,
   378→	const char *b
   379→)
   380→{
   381→	if (!a || !b)
   382→		return a;
   383→	
   384→	while ((*a++ = *b++)) ;
   385→	return a-1;
   386→}
   387→
   388→/* strncopy is like strcpy except it returns a pointer to the trailing NUL of
   389→ * the result string. This allows fast construction of catenated strings
   390→ * without the overhead of strlen/strcat.
   391→ */
   392→char *
   393→lutil_strncopy(
   394→	char *a,
   395→	const char *b,
   396→	size_t n
   397→)
   398→{
   399→	if (!a || !b || n == 0)
   400→		return a;
   401→	
   402→	while ((*a++ = *b++) && n-- > 0) ;
   403→	return a-1;
   404→}
   405→
   406→/* memcopy is like memcpy except it returns a pointer to the byte past
   407→ * the end of the result buffer, set to NULL. This allows fast construction
   408→ * of catenated buffers.  Provided for API consistency with lutil_str*copy().
   409→ */
   410→char *
   411→lutil_memcopy(
   412→	char *a,
   413→	const char *b,
   414→	size_t n
   415→)
   416→{
   417→	AC_MEMCPY(a, b, n);
   418→	return a + n;
   419→}
