   434→ * @param lastError[in] Result of GetLastError().
   435→ */
   436→static errno_t win2errno(DWORD lastError)
   437→{
   438→	const struct { 
   439→		DWORD   windows_code;
   440→		errno_t errno_code;
   441→	} WIN2ERRNO_TABLE[] = {
   442→		{ ERROR_SUCCESS, 0 },
   443→		{ ERROR_FILE_NOT_FOUND, ENOENT },
   444→		{ ERROR_PATH_NOT_FOUND, ENOENT },
   445→		{ ERROR_TOO_MANY_OPEN_FILES, EMFILE },
   446→		{ ERROR_ACCESS_DENIED, EACCES },
   447→		{ ERROR_INVALID_HANDLE, EBADF },
   448→		{ ERROR_NOT_ENOUGH_MEMORY, ENOMEM },
   449→		{ ERROR_LOCK_VIOLATION, EACCES },
   450→		{ ERROR_FILE_EXISTS, EEXIST },
   451→		{ ERROR_INVALID_PARAMETER, EINVAL },
   452→		{ ERROR_FILENAME_EXCED_RANGE, ENAMETOOLONG },
   453→	};
   454→	const unsigned int WIN2ERRNO_TABLE_SIZE = sizeof(WIN2ERRNO_TABLE) /
   455→sizeof(WIN2ERRNO_TABLE[0]);
   456→	const errno_t DEFAULT_ERRNO_ERROR = -1;
   457→	unsigned int i;
   458→
   459→	for (i = 0; i < WIN2ERRNO_TABLE_SIZE; ++i) {
   460→		if (WIN2ERRNO_TABLE[i].windows_code == lastError) {
   461→			return WIN2ERRNO_TABLE[i].errno_code;
   462→		}
   463→	}
   464→	return DEFAULT_ERRNO_ERROR;
   465→}
