   743→/* Multiply an integer by 100000000 and add new */
   744→typedef struct lutil_int_decnum {
   745→	unsigned char *buf;
   746→	int bufsiz;
   747→	int beg;
   748→	int len;
   749→} lutil_int_decnum;
   750→
   751→#define	FACTOR1	(100000000&0xffff)
   752→#define FACTOR2 (100000000>>16)
   753→
   754→static void
   755→scale( int new, lutil_int_decnum *prev, unsigned char *tmp )
   756→{
   757→	int i, j;
   758→	unsigned char *in = prev->buf+prev->beg;
   759→	unsigned int part;
   760→	unsigned char *out = tmp + prev->bufsiz - prev->len;
   761→
   762→	memset( tmp, 0, prev->bufsiz );
   763→	if ( prev->len ) {
   764→		for ( i = prev->len-1; i>=0; i-- ) {
   765→			part = in[i] * FACTOR1;
   766→			for ( j = i; part; j-- ) {
   767→				part += out[j];
   768→				out[j] = part & 0xff;
   769→				part >>= 8;
   770→			}
   771→			part = in[i] * FACTOR2;
   772→			for ( j = i-2; part; j-- ) {
   773→				part += out[j];
   774→				out[j] = part & 0xff;
   775→				part >>= 8;
   776→			}
   777→		}
   778→		j++;
   779→		prev->beg += j;
   780→		prev->len -= j;
   781→	}
   782→
   783→	out = tmp + prev->bufsiz;
   784→	i = 0;
   785→	do {
   786→		i--;
   787→		new += out[i];
   788→		out[i] = new & 0xff;
   789→		new >>= 8;
   790→	} while ( new );
   791→	i = -i;
   792→	if ( prev->len < i ) {
   793→		prev->beg = prev->bufsiz - i;
   794→		prev->len = i;
   795→	}
   796→	AC_MEMCPY( prev->buf+prev->beg, tmp+prev->beg, prev->len );
   797→}
