   799→/* Convert unlimited length decimal or hex string to binary.
   800→ * Output buffer must be provided, bv_len must indicate buffer size
   801→ * Hex input can be "0x1234" or "'1234'H"
   802→ *
   803→ * Note: High bit of binary form is always the sign bit. If the number
   804→ * is supposed to be positive but has the high bit set, a zero byte
   805→ * is prepended. It is assumed that this has already been handled on
   806→ * any hex input.
   807→ */
   808→int
   809→lutil_str2bin( struct berval *in, struct berval *out, void *ctx )
   810→{
   811→	char *pin, *pout;
   812→	char *end;
   813→	int i, chunk, len, rc = 0, hex = 0;
   814→	if ( !out || !out->bv_val || out->bv_len < in->bv_len )
   815→		return -1;
   816→
   817→	pout = out->bv_val;
   818→	/* Leading "0x" for hex input */
   819→	if ( in->bv_len > 2 && in->bv_val[0] == '0' &&
   820→		( in->bv_val[1] == 'x' || in->bv_val[1] == 'X' ) )
   821→	{
   822→		len = in->bv_len - 2;
   823→		pin = in->bv_val + 2;
   824→		hex = 1;
   825→	} else if ( in->bv_len > 3 && in->bv_val[0] == '\'' &&
   826→		in->bv_val[in->bv_len-2] == '\'' &&
   827→		in->bv_val[in->bv_len-1] == 'H' )
   828→	{
   829→		len = in->bv_len - 3;
   830→		pin = in->bv_val + 1;
   831→		hex = 1;
   832→	}
   833→	if ( hex ) {
   834→#define HEXMAX	(2 * sizeof(long))
   835→		unsigned long l;
   836→		char tbuf[HEXMAX+1];
   837→
   838→		/* Convert a longword at a time, but handle leading
   839→		 * odd bytes first
   840→		 */
   841→		chunk = len % HEXMAX;
   842→		if ( !chunk )
   843→			chunk = HEXMAX;
   844→
   845→		while ( len ) {
   846→			int ochunk;
   847→			memcpy( tbuf, pin, chunk );
   848→			tbuf[chunk] = '\0';
   849→			errno = 0;
   850→			l = strtoul( tbuf, &end, 16 );
   851→			if ( errno )
   852→				return -1;
   853→			ochunk = (chunk + 1)/2;
   854→			for ( i = ochunk - 1; i >= 0; i-- ) {
   855→				pout[i] = l & 0xff;
   856→				l >>= 8;
   857→			}
   858→			pin += chunk;
   859→			pout += ochunk;
   860→			len -= chunk;
   861→			chunk = HEXMAX;
   862→		}
   863→		out->bv_len = pout - out->bv_val;
   864→	} else {
   865→	/* Decimal */
   866→#define	DECMAX	8	/* 8 digits at a time */
   867→		char tmpbuf[64], *tmp;
   868→		lutil_int_decnum num;
   869→		int neg = 0;
   870→		long l;
   871→		char tbuf[DECMAX+1];
   872→
   873→		len = in->bv_len;
   874→		pin = in->bv_val;
   875→		num.buf = (unsigned char *)out->bv_val;
   876→		num.bufsiz = out->bv_len;
   877→		num.beg = num.bufsiz-1;
   878→		num.len = 0;
   879→		if ( pin[0] == '-' ) {
   880→			neg = 0xff;
   881→			len--;
   882→			pin++;
   883→		}
   884→
   885→		/* tmp must be at least as large as outbuf */
   886→		if ( out->bv_len > sizeof(tmpbuf)) {
   887→			tmp = ber_memalloc_x( out->bv_len, ctx );
   888→		} else {
   889→			tmp = tmpbuf;
   890→		}
   891→		chunk = len & (DECMAX-1);
   892→		if ( !chunk )
   893→			chunk = DECMAX;
   894→
   895→		while ( len ) {
   896→			memcpy( tbuf, pin, chunk );
   897→			tbuf[chunk] = '\0';
   898→			errno = 0;
   899→			l = strtol( tbuf, &end, 10 );
   900→			if ( errno ) {
   901→				rc = -1;
   902→				goto decfail;
   903→			}
   904→			scale( l, &num, (unsigned char *)tmp );
   905→			pin += chunk;
   906→			len -= chunk;
   907→			chunk = DECMAX;
   908→		}
   909→		/* Negate the result */
   910→		if ( neg ) {
   911→			unsigned char *ptr;
   912→
   913→			ptr = num.buf+num.beg;
   914→
   915→			/* flip all bits */
   916→			for ( i=0; i<num.len; i++ )
   917→				ptr[i] ^= 0xff;
   918→
   919→			/* add 1, with carry - overflow handled below */
   920→			while ( i-- && ! (ptr[i] = (ptr[i] + 1) & 0xff )) ;
   921→		}
   922→		/* Prepend sign byte if wrong sign bit */
   923→		if (( num.buf[num.beg] ^ neg ) & 0x80 ) {
   924→			num.beg--;
   925→			num.len++;
   926→			num.buf[num.beg] = neg;
   927→		}
   928→		if ( num.beg )
   929→			AC_MEMCPY( num.buf, num.buf+num.beg, num.len );
   930→		out->bv_len = num.len;
   931→decfail:
   932→		if ( tmp != tmpbuf ) {
   933→			ber_memfree_x( tmp, ctx );
   934→		}
   935→	}
   936→	return rc;
   937→}
