   941→/* Used to parse and unparse time intervals, not timestamps */
   942→int
   943→lutil_parse_time(
   944→	const char	*in,
   945→	unsigned long	*tp )
   946→{
   947→	unsigned long	t = 0;
   948→	char		*s,
   949→			*next;
   950→	int		sofar = -1,
   951→			scale[] = { 86400, 3600, 60, 1 };
   952→
   953→	*tp = 0;
   954→
   955→	for ( s = (char *)in; s[ 0 ] != '\0'; ) {
   956→		unsigned long	u;
   957→		char		*what;
   958→
   959→		/* strtoul() has an odd interface */
   960→		if ( s[ 0 ] == '-' ) {
   961→			return -1;
   962→		}
   963→
   964→		u = strtoul( s, &next, 10 );
   965→		if ( next == s ) {
   966→			return -1;
   967→		}
   968→
   969→		if ( next[ 0 ] == '\0' ) {
   970→			/* assume seconds */
   971→			t += u;
   972→			break;
   973→		}
   974→
   975→		what = strchr( time_unit, next[ 0 ] );
   976→		if ( what == NULL ) {
   977→			return -1;
   978→		}
   979→
   980→		if ( what - time_unit <= sofar ) {
   981→			return -1;
   982→		}
   983→
   984→		sofar = what - time_unit;
   985→		t += u * scale[ sofar ];
   986→
   987→		s = &next[ 1 ];
   988→	}
   989→
   990→	*tp = t;
   991→	return 0;
   992→}
   993→
   994→int
   995→lutil_unparse_time(
   996→	char			*buf,
   997→	size_t			buflen,
   998→	unsigned long		t )
   999→{
  1000→	int		len, i;
  1001→	unsigned long	v[ 4 ];
  1002→	char		*ptr = buf;
  1003→
  1004→	v[ 0 ] = t/86400;
  1005→	v[ 1 ] = (t%86400)/3600;
  1006→	v[ 2 ] = (t%3600)/60;
  1007→	v[ 3 ] = t%60;
  1008→
  1009→	for ( i = 0; i < 4; i++ ) {
  1010→		if ( v[i] > 0 || ( i == 3 && ptr == buf ) ) {
  1011→			len = snprintf( ptr, buflen, "%lu%c", v[ i ], time_unit[ i ] );
  1012→			if ( len < 0 || (unsigned)len >= buflen ) {
  1013→				return -1;
  1014→			}
  1015→			buflen -= len;
  1016→			ptr += len;
  1017→		}
  1018→	}
  1019→
  1020→	return 0;
  1021→}
