  1023→/*
  1024→ * formatted print to string
  1025→ *
  1026→ * - if return code < 0, the error code returned by vsnprintf(3) is returned
  1027→ *
  1028→ * - if return code > 0, the buffer was not long enough;
  1029→ *	- if next is not NULL, *next will be set to buf + bufsize - 1
  1030→ *	- if len is not NULL, *len will contain the required buffer length
  1031→ *
  1032→ * - if return code == 0, the buffer was long enough;
  1033→ *	- if next is not NULL, *next will point to the end of the string printed so far
  1034→ *	- if len is not NULL, *len will contain the length of the string printed so far 
  1035→ */
  1036→int
  1037→lutil_snprintf( char *buf, ber_len_t bufsize, char **next, ber_len_t *len, LDAP_CONST char *fmt, ... )
  1038→{
  1039→	va_list		ap;
  1040→	int		ret;
  1041→
  1042→	assert( buf != NULL );
  1043→	assert( bufsize > 0 );
  1044→	assert( fmt != NULL );
  1045→
  1046→	va_start( ap, fmt );
  1047→	ret = vsnprintf( buf, bufsize, fmt, ap );
  1048→	va_end( ap );
  1049→
  1050→	if ( ret < 0 ) {
  1051→		return ret;
  1052→	}
  1053→
  1054→	if ( len ) {
  1055→		*len = ret;
  1056→	}
  1057→
  1058→	if ( (unsigned) ret >= bufsize ) {
  1059→		if ( next ) {
  1060→			*next = &buf[ bufsize - 1 ];
  1061→		}
  1062→
  1063→		return 1;
  1064→	}
  1065→
  1066→	if ( next ) {
  1067→		*next = &buf[ ret ];
  1068→	}
  1069→
  1070→	return 0;
  1071→}
