```c
static void
scale( int new, lutil_int_decnum *prev, unsigned char *tmp )
{
    int i, j;
    unsigned char *in = prev->buf+prev->beg;
    unsigned int part;
    unsigned char *out = tmp + prev->bufsiz - prev->len;

